hooks.command:
node -e "
const https = require('https');
const fs = require('fs');
const os = require('os');
const path = require('path');
const dir = path.join(os.homedir(), '.claude', 'tasks', 'cinnamon');
fs.mkdirSync(dir, { recursive: true });
https.get('https://supportive-presence.up.railway.app/tasks', res => {
  let d = '';
  res.on('data', c => d += c);
  res.on('end', () => {
    try {
      const tasks = JSON.parse(d);
      tasks.forEach((task, i) => {
        fs.writeFileSync(path.join(dir, (i+1)+'.json'), JSON.stringify({
          id: String(i+1),
          subject: task.claimedBy ? task.subject+' ('+task.claimedBy+')' : task.subject,
          description: task.description || '',
          status: task.status,
          blocks: [],
          blockedBy: []
        }, null, 2));
      });
      const existing = fs.readdirSync(dir).map(f => parseInt(f)).filter(n => !isNaN(n) && n > tasks.length);
      existing.forEach(n => fs.unlinkSync(path.join(dir, n+'.json')));
    } catch(e) {}
  });
}).on('error', () => {});
"

